const all = $input.first().json.result || [];
const anomalies = all.filter(w => w.is_silent_anomaly);
const sliced = anomalies.slice(0, 5);  // cap at 5 per day to keep CEO sane

return sliced.map(w => ({
  json: {
    whale: w,
    prompt: `You are the personal-touch agent for Gaming Goods, a digital goods marketplace. Generate a SHORT message in Russian for the CEO Кирилл to send to a whale customer who has gone silent.

Customer profile:
- User ID: ${w.user_id.slice(0,8)}...
- Last order: ${w.last_order} (silent ${w.silent_days} days)
- Average interval between orders: ${w.avg_interval_days} days (so silent is ${(w.silent_days/Math.max(w.avg_interval_days,1)).toFixed(1)}× normal)
- 90-day GMV: €${w.gmv_eur_90d}
- Orders in 90d: ${w.orders_90d}
- Average ticket: €${w.avg_aov_eur}
- Favorite brand: ${w.fav_brand || 'mixed'}

Write the message body ONLY (no greeting, no signature). Tone: warm, short, business. 3-4 sentences max. Offer something concrete (5% lifetime discount, or first-mover access to new arrivals, depending on profile). Speak as Кирилл, founder.

Return JSON object: {"text": "...", "channel": "telegram|email", "offer_code": "TY-XXX-5", "why_now": "one-line reason"}.`
  }
}));

const resp = $input.first().json;
const whaleData = $('Find anomalies').item.json.whale;
const text = (resp.content && resp.content[0] && resp.content[0].text) || '';
let parsed;
try {
  // try JSON-only response
  parsed = JSON.parse(text);
} catch(e) {
  // fallback: extract text block
  parsed = { text: text, channel: 'telegram', offer_code: 'TY-VIP-5', why_now: 'silent ' + whaleData.silent_days + ' days' };
}

return [{
  json: {
    agent_name: 'whale_personal',
    action_type: 'whale_touch',
    preview: 'Whale touch: ' + whaleData.user_id.slice(0,8) + '... · €' + whaleData.gmv_eur_90d + ' / 90d · silent ' + whaleData.silent_days + 'd',
    payload: {
      user_id: whaleData.user_id,
      gmv_eur_90d: whaleData.gmv_eur_90d,
      silent_days: whaleData.silent_days,
      avg_interval: whaleData.avg_interval_days,
      fav_brand: whaleData.fav_brand,
      message: parsed.text,
      channel: parsed.channel || 'telegram',
      offer_code: parsed.offer_code || 'TY-VIP-5'
    },
    approval_required: true,
    sla: '24 hours',
    why_now: parsed.why_now || ('Silent ' + whaleData.silent_days + ' days vs ' + whaleData.avg_interval_days + ' avg')
  }
}];
